#include<bits/stdc++.h>
using namespace std;
int main() {
	string a1, b2, t;
	int a[10001] = {0}, b[10001] = {0}, c[100001] = {0}, len;
	char g = ' ';

	cin >> a1 >> b2;
	if (a1==b2) {
		cout << "0";
		return 0;
	}
	if ((a1 < b2 && a1.size() == b2.size()) || a1.size() < b2.size()) {
		g = '-';
		t = a1;
		a1 = b2;
		b2 = t;
	}
	len = max(a1.size(), b2.size());
	for (int i = 0; i < a1.size(); i++) {
		a[i] = a1[a1.size() - i - 1] - '0';
	}
	for (int i = 0; i < b2.size(); i++) {
		b[i] = b2[b2.size() - i - 1] - '0';
	}

	for (int i = 0; i < len; i++) {
		c[i] += a[i] - b[i];
		if (c[i] < 0) {
			c[i + 1] = -1;
			c[i] = c[i] + 10;
		}
	}
	for (; c[len] == 0;) {
		len--;
	}
	if (g == '-') {
		cout << g;
	}
	for (int i = len; i >= 0; i--) {
		cout << c[i];
	}
	return 0;
}
